insert into public.workout_templates (id, name, main_goal, level, days_per_week, num_workouts, description, source)
values ('5c55f318-f7d6-4574-837c-4206b4572058'::uuid, 'Campo de treinamento militar', 'Perder Gordura', 'Iniciante', 4, 2, 'Cada treino consiste de um circuito que deixará você encharcado de suor. Realize os treinos durante 4 dias por semana, alternando entre Treino A e Treino B.', 'gymday')
on conflict (id) do update set
