insert into public.workout_templates (id, name, main_goal, level, days_per_week, num_workouts, description, source)
values ('341b2a72-165c-427f-9bce-90aeae19d5c9'::uuid, 'Construtor de Músculos Magros: Treino PPL de 3 Dias', 'Hipertrofia', 'Intermediário', 3, 3, 'Esse treino dividido em push, pull e legs é um programa simples e equilibrado de três dias que trabalha todos os principais grupos musculares, permitindo tempo suficiente para recuperação, crescimento e força.

No dia de push, o foco está no peito, ombros e tríceps, cobrindo todos os movimentos de empurrar. Já no dia de pull, as costas e os bíceps são treinados com exercícios voltados para força de puxada.

O último dia é dedicado às pernas, com ênfase em potência e estabilidade através de agachamentos e exercícios acessórios complementares. Essa abordagem mantém cada treino focado, eficiente e atlético, ajudando você a se manter consistente e a progredir de forma constante semana após semana.', 'gymday')
on conflict (id) do update set
  name = excluded.name,
  main_goal = excluded.main_goal,
  level = excluded.level,
  days_per_week = excluded.days_per_week,
  num_workouts = excluded.num_workouts,
  description = excluded.description;

insert into public.workout_templates (id, name, main_goal, level, days_per_week, num_workouts, description, source)
values ('2bfeb5c0-6771-47f8-b6dc-af63d96bff6c'::uuid, 'Corpo de verão', 'Hipertrofia', 'Intermediário', 3, 3, 'O verão está chegando e você deseja curtir ao ar livre com sua família e amigos, e ainda assim ter tempo de construir um ótimo físico. Este plano de 3 dias contém treinos eficientes que utilizam exercícios compostos e de isolamento, permitindo que você construa músculos sem passar horas na academia.', 'gymday')
on conflict (id) do update set
  name = excluded.name,
  main_goal = excluded.main_goal,
  level = excluded.level,
  days_per_week = excluded.days_per_week,
  num_workouts = excluded.num_workouts,
  description = excluded.description;

insert into public.workout_templates (id, name, main_goal, level, days_per_week, num_workouts, description, source)
values ('55c9df19-f8f4-40fb-b7a2-968348fc839e'::uuid, 'Desafio de Verão: Plano de 5 Dias', 'Hipertrofia', 'Intermediário', 5, 5, 'Por anos, procurei a divisão de treino perfeita para alcançar o corpo dos meus sonhos—focando no aumento de massa, levantando pesado, e dizendo a mim mesmo que o peso extra acabaria virando músculo. Em vez disso, fiquei inchado, lento, e constantemente prometendo que iria "cortar depois" para que o músculo aparecesse.

Após dois anos, percebi que precisava de um plano que promovesse o crescimento muscular sem sacrificar a definição ou a estética. Foi assim que criei meu plano de treino de 5 dias—um guia para ganhar massa magra, projetado para desenvolver músculos densos e atléticos, mantendo o percentual de gordura baixo e os níveis de energia elevados.

Este plano de 5 dias é para quem quer resultados reais: treinamento focado em hipertrofia com intensidade suficiente, estrutura e recuperação inteligente para manter seu físico em forma. A cada dia, trabalhamos grupos musculares específicos com equilíbrio entre exercícios compostos, séries volumosas e finalizações metabólicas para te manter enxuto. Prepare-se para treinar forte, suar mais que o usual e voltar a se olhar no espelho com satisfação. Seja saindo de uma fase de hipertrofia ou apenas querendo elevar seu treino, este plano é sua ponte entre parecer forte e ser forte.', 'gymday')
on conflict (id) do update set
  name = excluded.name,
  main_goal = excluded.main_goal,
  level = excluded.level,
  days_per_week = excluded.days_per_week,
  num_workouts = excluded.num_workouts,
  description = excluded.description;

insert into public.workout_templates (id, name, main_goal, level, days_per_week, num_workouts, description, source)
values ('b3aa03cc-0190-411d-a4ae-383da1babea1'::uuid, 'Divisão Arnold 5 Dias PPL', 'Hipertrofia', 'Intermediário', 5, 5, 'Este plano de treino foi elaborado para maximizar o ganho de massa magra enquanto melhora a força e o condicionamento geral. Organizado em uma divisão de cinco dias, combina movimentos de empurrar, puxar e de pernas, com um dia extra focado no peito e nas costas, além de um dia final dedicado a ombros e braços.

Cada sessão enfatiza um equilíbrio entre exercícios compostos para ganho de massa e exercícios de isolamento, supersets e séries AMRAP (o máximo de repetições possíveis) para melhorar a definição muscular e a resistência. Os intervalos de descanso são estrategicamente definidos entre 60 e 120 segundos para otimizar a recuperação sem comprometer a intensidade.

O plano integra os princípios clássicos de volume elevado e treinamento frequente ao estilo Arnold, sendo ideal para praticantes intermediários que desejam construir um físico magro e musculoso. A combinação de supersets, variação de faixas de repetições e movimentos de isolamento direcionados assegura que todos os principais grupos musculares sejam trabalhados de forma eficaz várias vezes por semana, estimulando a hipertrofia e mantendo a saúde das articulações e a força funcional.

Seja para esculpir um físico equilibrado e forte ou para aumentar a massa muscular total, este plano oferece uma estrutura organizada e desafiadora para um progresso consistente.', 'gymday')
on conflict (id) do update set
  name = excluded.name,
  main_goal = excluded.main_goal,
  level = excluded.level,
  days_per_week = excluded.days_per_week,
  num_workouts = excluded.num_workouts,
  description = excluded.description;

insert into public.workout_templates (id, name, main_goal, level, days_per_week, num_workouts, description, source)
values ('d56d4326-6df2-4efb-badd-7ca98117c2ab'::uuid, 'Divisão Upper/Lower para a dor lombar', 'Hipertrofia', 'Intermediário', 4, 4, 'Pronto para desenvolver músculos e, simultaneamente, manter a região lombar protegida e apoiada? Esse programa foi desenvolvido especificamente para quem deseja treinar intensamente sem comprometer a saúde da coluna. 

Esse programa elaborado criteriosamente foca em exercícios eficazes e de baixo impacto voltados para todos os principais grupos musculares, minimizando a tensão na coluna. Assim, você fortalecerá seu tronco, aumentará a estabilidade e alcançará impressionantes ganhos musculares - tudo isso protegendo a região lombar. 

Se está se recuperando de uma lesão ou apenas procurando uma maneira mais segura de treinar, este programa tem tudo o que você precisa.', 'gymday')
on conflict (id) do update set
  name = excluded.name,
  main_goal = excluded.main_goal,
  level = excluded.level,
  days_per_week = excluded.days_per_week,
  num_workouts = excluded.num_workouts,
  description = excluded.description;

