insert into public.workout_templates (id, name, main_goal, level, days_per_week, num_workouts, description, source)
values ('3508b61d-1f61-4d90-a005-882e358f199d'::uuid, 'Princípios básicos das mulheres', 'Hipertrofia', 'Iniciante', 3, 3, 'Um dinâmico programa de musculação, criado especificamente para empoderar mulheres de todos os níveis de aptidão física. 

Esse programa tem como foco o desenvolvimento da força, a obtenção de massa muscular magra e o aperfeiçoamento do desempenho atlético global. Com uma abordagem específica para áreas-chave, por exemplo glúteos, pernas e tronco, este programa ajuda você a definir uma base sólida para evoluir a longo prazo. 

Todos os exercícios são elaborados criteriosamente para que você sinta maior motivação, para promover o crescimento muscular e aumentar a confiança, quer você esteja só começando, quer pretenda aprimorar seu treinamento. Vamos lançar as bases para você ficar mais forte e saudável!', 'gymday')
on conflict (id) do update set
  name = excluded.name,
