insert into public.workout_templates (id, name, main_goal, level, days_per_week, num_workouts, description, source)
values ('d7e43364-9f8c-4e16-80f4-af44a4909563'::uuid, 'Princípios básicos do fisiculturismo', 'Hipertrofia', 'Iniciante', 3, 3, 'Um programa de treino simplificado, desenvolvido para enfatizar os treinos fundamentais que constroem uma estrutura sólida para o crescimento e a força musculares. 

Esse programa destaca os principais movimentos do tronco, como agachamentos, levantamentos terra, supinos e remadas, que têm como alvo diversos grupos musculares para máxima eficiência. 

A abordagem equilibrada ao volume, à intensidade e à recuperação garante a sobrecarga progressiva e minimiza complexidades desnecessárias. 

Com um perfil perfeito para iniciantes que querem estabelecer uma base robusta ou para pessoas experientes que querem aperfeiçoar sua postura e aumentar a força, este programa tem como objetivo dominar os fundamentos básicos para obter resultados duradouros.', 'gymday')
