insert into public.workout_templates (id, name, main_goal, level, days_per_week, num_workouts, description, source)
values ('d0e3493b-5708-47a2-b82f-0a7f9b1885b5'::uuid, 'Treinamento híbrido', 'Perder Gordura', 'Avançado', 5, 5, 'Esse programa foi desenvolvido para as pessoas que buscam ter tudo - força, desenvolvimento muscular, condicionamento e aptidão funcional - em um eficiente formato de 60 minutos. 

Cada treino inclui exercícios de força de alto impacto, trabalho de hipertrofia e intensos circuitos de condicionamento que irão desafiar sua resistência e desenvolver os músculos de todos os ângulos. 

Esse programa foi desenvolvido para manter você em atividade com um propósito, superando seus limites e mantendo suas sessões de treinamento interessantes e eficazes. 

Quer você esteja levantando pesos, fazendo um circuito ou focando na força do tronco, este plano tem como objetivo maximizar os resultados no menor tempo possível. Vamos preparar você para se sentir mais forte, mais vigoroso e mais bem preparado do que nunca!', 'gymday')
on conflict (id) do update set
  name = excluded.name,
  main_goal = excluded.main_goal,
  level = excluded.level,
  days_per_week = excluded.days_per_week,
  num_workouts = excluded.num_workouts,
  description = excluded.description;

insert into public.workout_templates (id, name, main_goal, level, days_per_week, num_workouts, description, source)
values ('0bff49b5-2e49-400e-a611-6ca7f9b6a26e'::uuid, 'Treino híbrido de 6 dias', 'Hipertrofia', 'Avançado', 6, 6, 'Sou atleta desde sempre, tendo crescido no ambiente de esportes de alto rendimento e treinado em várias modalidades. Este programa combina estética, força e desempenho híbrido para ajudá-lo a desenvolver um físico poderoso e versátil.', 'gymday')
on conflict (id) do update set
